values ('b1000000-0000-4000-8000-000000000001', null, 'Lemon Herb Chicken and Vegetable Traybake', 'A bright one-tray dinner with juicy chicken, crisp-edged potatoes and flexible vegetables. Ideal for using carrots, peppers or onions before they spoil; cooked leftovers can be used in wraps, salads or fried rice.', 15, 45, 4, array['meat', 'high-protein', 'one-pan', 'meal-prep', 'gluten-free', 'food-smart']::text[], array['Preheat the oven to 210°C, or 190°C fan. Cut the potatoes, carrots, pepper and onion into similar bite-size pieces.', 'Spread the vegetables on a large baking tray. Add 1 tablespoon of olive oil, half the oregano, half the paprika, salt and black pepper, then toss well.', 'Pat the chicken dry. Rub it with the remaining olive oil, oregano, paprika, garlic, lemon zest and a little salt and pepper.', 'Place the chicken among the vegetables and roast for 35 minutes.', 'Turn the vegetables, squeeze over the lemon juice and roast for another 10 minutes, or until the vegetables are tender and the chicken is fully cooked.', 'Rest for 5 minutes before serving. Cool any leftovers promptly and refrigerate in a covered container.']::text[], null, 'dinner', 'Chicken', 'easy', true, null, 'pending', 'Appetizing lemon herb chicken thigh traybake with golden baby potatoes, roasted carrots, red pepper and red onion, fresh lemon wedges and parsley, warm natural daylight, modern rustic ceramic plate, cream linen background, realistic editorial food photography, overhead three-quarter view, no text, no people', 1, 'cloudflare_r2', 520, 21, 145, 40, 9, 650, 45, 8, null)
