values ('b1000000-0000-4000-8000-000000000002', null, 'Smoky Turkey and Bean Chili', 'A comforting one-pot chili with lean turkey, beans and vegetables. It freezes well, stretches a modest amount of meat across four portions and is excellent over rice, potatoes or in wraps.', 15, 35, 4, array['meat', 'high-protein', 'high-fiber', 'one-pot', 'freezer-friendly', 'meal-prep']::text[], array['Heat the olive oil in a large saucepan over medium heat. Add the onion, carrot and pepper, then cook for 6 to 8 minutes until softened.', 'Add the turkey mince and cook for 5 minutes, breaking it into small pieces, until no pink remains.', 'Stir in the garlic, smoked paprika, cumin and chili powder and cook for 30 seconds.', 'Add the chopped tomatoes, drained beans and stock. Bring to a gentle boil, then reduce the heat.', 'Simmer uncovered for 20 minutes, stirring occasionally, until thick and rich. Add a splash of water if it becomes too dry.', 'Season to taste and finish with lime juice. Divide into portions; cool promptly before refrigerating or freezing.']::text[], null, 'dinner', 'Turkey', 'easy', true, null, 'pending', 'Rich smoky turkey and red bean chili in a matte ceramic bowl, visible tomato, red pepper and beans, lime wedge, small spoonful of yogurt and coriander garnish, cozy natural light, cream tabletop, realistic premium food photography, three-quarter overhead view, no text, no people', 1, 'cloudflare_r2', 430, 12, 95, 38, 11, 720, 42, 11, null)
