values ('b1000000-0000-4000-8000-000000000003', null, 'One-Pan Beef, Tomato and Spinach Orzo', 'A cozy all-in-one pasta with lean beef, tomato and spinach. The spinach can be replaced by any tender greens that need using, while grated carrot disappears into the sauce.', 10, 25, 4, array['meat', 'one-pan', 'family-friendly', 'high-protein', 'hidden-veg', 'meal-prep']::text[], array['Heat the olive oil in a wide, deep pan over medium-high heat. Add the beef and cook for 5 minutes, breaking it up, until browned.', 'Add the onion and grated carrot and cook for 5 minutes. Stir in the garlic and oregano for 30 seconds.', 'Add the orzo, chopped tomatoes and stock. Stir well and bring to a gentle simmer.', 'Cook uncovered for 10 to 12 minutes, stirring frequently so the orzo does not stick, until tender. Add small splashes of water if needed.', 'Fold in the spinach and cook for 2 minutes until wilted. Stir in half the Parmesan.', 'Season to taste and serve with the remaining Parmesan. Cool leftovers promptly in shallow containers.']::text[], null, 'dinner', 'Beef', 'easy', true, null, 'pending', 'Creamy beef tomato and spinach orzo in a shallow sage ceramic bowl, visible small pasta grains, lean minced beef, wilted spinach and grated parmesan, warm natural window light, cream background, inviting realistic editorial food photography, no text, no people', 1, 'cloudflare_r2', 520, 16, 85, 35, 10, 680, 58, 9, null)
