values ('b1000000-0000-4000-8000-000000000004', null, 'Leftover Chicken Vegetable Fried Rice', 'A fast, flexible meal designed for safely chilled cooked rice and leftover chicken. Frozen vegetables make it practical, while fresh carrots or peppers can be added whenever they need using.', 10, 15, 4, array['meat', 'leftovers', 'quick', 'one-pan', 'food-smart', 'high-protein']::text[], array['Use cooked rice that was cooled promptly and refrigerated. Break up any clumps before starting.', 'Heat 1 tablespoon of oil in a large wok or frying pan over high heat. Add the beaten eggs, scramble briefly, then transfer to a plate.', 'Add the remaining oil, carrot and the white parts of the spring onions. Stir-fry for 2 minutes.', 'Add the frozen peas, cooked chicken and garlic. Stir-fry for another 2 to 3 minutes until piping hot.', 'Add the rice and stir-fry for 4 minutes, tossing frequently. Return the egg to the pan.', 'Add the soy sauce, sesame oil and green spring onion tops. Toss well and serve immediately with lime wedges.']::text[], null, 'lunch', 'Chicken', 'easy', true, null, 'pending', 'Colorful chicken vegetable fried rice in a dark shallow bowl, separate golden rice grains, tender chicken, peas, carrot, scrambled egg and spring onion, lime wedge, bright natural light, warm minimalist table styling, realistic food photography, no text, no people', 1, 'cloudflare_r2', 470, 13, 150, 35, 6, 780, 52, 6, null)
