values ('b1000000-0000-4000-8000-000000000005', null, 'Turkey Meatballs in Tomato Spinach Sauce', 'Tender oven-baked turkey meatballs in a simple tomato sauce with spinach. Make a double batch for the freezer or serve leftovers in a sandwich, wrap or grain bowl.', 20, 30, 4, array['meat', 'high-protein', 'freezer-friendly', 'meal-prep', 'family-friendly', 'batch-cooking']::text[], array['Preheat the oven to 210°C, or 190°C fan. Line a baking tray with baking paper.', 'Mix the turkey, breadcrumbs, egg, half the garlic, half the oregano, half the Parmesan, salt and pepper. Shape into 16 meatballs without compacting the mixture too firmly.', 'Place the meatballs on the tray, brush with half the olive oil and bake for 15 minutes.', 'Meanwhile, heat the remaining oil in a large pan. Cook the onion for 5 minutes, then add the remaining garlic and oregano for 30 seconds.', 'Add the passata and simmer for 10 minutes. Add the baked meatballs and simmer gently for another 8 minutes, or until fully cooked.', 'Fold in the spinach until wilted. Serve with the remaining Parmesan and your choice of pasta, rice or crusty bread.']::text[], null, 'dinner', 'Turkey', 'easy', true, null, 'pending', 'Golden turkey meatballs in rich tomato spinach sauce in a cream ceramic serving bowl, parmesan and basil garnish, a little crusty bread at the side, warm inviting natural light, refined realistic food photography, no text, no people', 1, 'cloudflare_r2', 390, 15, 125, 42, 9, 690, 22, 5, null)
