values ('b1000000-0000-4000-8000-000000000006', null, 'Red Lentil, Sweet Potato and Spinach Curry', 'A creamy, deeply flavored vegetarian curry made mostly from pantry staples. It freezes well and turns soft sweet potato or wilting spinach into a generous, satisfying meal.', 10, 30, 4, array['vegetarian', 'vegan', 'high-fiber', 'one-pot', 'freezer-friendly', 'gluten-free']::text[], array['Heat the oil in a large saucepan over medium heat. Cook the onion for 5 minutes until soft.', 'Add the garlic, ginger, curry powder, cumin and turmeric. Stir for 30 seconds until fragrant.', 'Add the sweet potato, rinsed lentils, chopped tomatoes, coconut milk and stock. Stir and bring to a gentle boil.', 'Reduce the heat, cover loosely and simmer for 20 to 25 minutes, stirring occasionally, until the lentils and sweet potato are tender.', 'Add a splash of water if the curry becomes too thick. Fold in the spinach and cook for 2 minutes.', 'Season to taste, add the lime juice and serve. Cool extra portions promptly before refrigerating or freezing.']::text[], null, 'dinner', 'Vegetarian', 'easy', true, null, 'pending', 'Creamy red lentil sweet potato and spinach curry in a handmade beige bowl, vivid golden orange sauce, tender sweet potato cubes, wilted greens, lime and coriander garnish, warm natural light, minimalist cream background, realistic appetizing food photography, no text, no people', 1, 'cloudflare_r2', 430, 15, 0, 17, 11, 590, 58, 14, null)
