values ('b1000000-0000-4000-8000-000000000007', null, 'Crispy Black Bean and Vegetable Quesadillas', 'Crisp tortillas filled with smoky beans, vegetables and melted cheese. A quick way to use half peppers, leftover corn, greens or herbs, and easy to customize for different households.', 15, 15, 4, array['vegetarian', 'quick', 'high-fiber', 'family-friendly', 'customizable', 'food-smart']::text[], array['Mash half the black beans with a fork, leaving the rest whole.', 'Heat the olive oil in a frying pan. Cook the onion and pepper for 5 minutes, then add the corn, cumin and smoked paprika for 2 minutes.', 'Stir in all the beans, lime juice and 2 tablespoons of water. Cook for 2 minutes, then season to taste.', 'Spread the filling over one half of each tortilla. Add the spinach and cheese, then fold closed.', 'Wipe the pan clean and cook the quesadillas in batches over medium heat for 2 to 3 minutes per side until crisp and the cheese has melted.', 'Cut into wedges and serve with yogurt, salsa or extra lime.']::text[], null, 'lunch', 'Vegetarian', 'easy', true, null, 'pending', 'Golden crisp black bean vegetable quesadilla wedges on a warm ceramic plate, visible melted cheddar, beans, corn, red pepper and spinach, lime wedge and fresh salsa, bright natural light, friendly modern food photography, cream background, no text, no people', 1, 'cloudflare_r2', 520, 20, 45, 22, 6, 800, 61, 14, null)
