values ('b1000000-0000-4000-8000-000000000008', null, 'Spinach, Mushroom and Potato Frittata', 'A satisfying oven frittata that rescues cooked potatoes, mushrooms and tender greens. It works for breakfast, lunch or dinner and tastes good warm or chilled.', 15, 25, 4, array['vegetarian', 'gluten-free', 'meal-prep', 'leftovers', 'high-protein', 'food-smart']::text[], array['Preheat the oven grill to medium-high. Beat the eggs with the milk, half the cheese, salt and pepper.', 'Heat the olive oil in a 24 cm oven-safe non-stick frying pan. Cook the onion and mushrooms for 6 to 8 minutes until golden and most moisture has evaporated.', 'Add the sliced cooked potatoes and spinach. Cook for 2 minutes until the spinach wilts.', 'Pour in the egg mixture and stir once to distribute the vegetables. Cook over low heat for 6 to 8 minutes until the edges are set but the top remains slightly wet.', 'Sprinkle over the remaining cheese and place under the grill for 3 to 5 minutes until puffed, golden and set in the center.', 'Rest for 5 minutes before slicing. Refrigerate cooled portions in a covered container.']::text[], null, 'breakfast', 'Vegetarian', 'easy', true, null, 'pending', 'Golden spinach mushroom and potato frittata sliced in an oven-safe skillet, visible mushrooms, greens and potato, small green salad beside it, soft morning daylight, warm cream and sage styling, realistic editorial food photography, no text, no people', 1, 'cloudflare_r2', 330, 20, 390, 24, 5, 500, 18, 4, null)
