values ('b1000000-0000-4000-8000-000000000009', null, 'Mediterranean Chickpea and Spinach Stew', 'A bright tomato-based chickpea stew with lemon and spinach. It relies on inexpensive pantry staples and is forgiving enough for courgette, peppers or other vegetables that need using.', 10, 25, 4, array['vegetarian', 'vegan', 'high-fiber', 'one-pot', 'gluten-free', 'pantry-friendly']::text[], array['Heat the olive oil in a large saucepan over medium heat. Cook the onion, carrot and pepper for 6 to 8 minutes until soft.', 'Add the garlic, smoked paprika and cumin and cook for 30 seconds.', 'Add the chopped tomatoes, chickpeas and stock. Bring to a gentle boil, then reduce the heat.', 'Simmer uncovered for 15 minutes. Lightly crush some chickpeas against the side of the pan to thicken the stew.', 'Fold in the spinach and cook for 2 minutes until wilted.', 'Add the lemon zest and juice, season to taste and serve with parsley and whole-grain bread or couscous if desired.']::text[], null, 'lunch', 'Vegetarian', 'easy', true, null, 'pending', 'Mediterranean chickpea tomato and spinach stew in a rustic light ceramic bowl, visible chickpeas, red pepper, carrot and wilted greens, lemon and parsley garnish, sunny natural daylight, cream linen, realistic wholesome food photography, no text, no people', 1, 'cloudflare_r2', 360, 10, 0, 16, 12, 620, 50, 15, null)
