values ('b1000000-0000-4000-8000-000000000010', null, 'Roasted Vegetable, Chickpea and Feta Couscous', 'A colorful, satisfying couscous bowl that makes almost any mix of roastable vegetables taste intentional. It is excellent warm or chilled and packs well for lunch the next day.', 15, 30, 4, array['vegetarian', 'meal-prep', 'high-fiber', 'lunchbox', 'customizable', 'food-smart']::text[], array['Preheat the oven to 220°C, or 200°C fan. Cut the courgette, pepper, carrots and onion into similar bite-size pieces.', 'Spread the vegetables and chickpeas over a large baking tray. Toss with the olive oil, cumin, smoked paprika, salt and pepper.', 'Roast for 25 to 30 minutes, turning once, until tender and browned at the edges.', 'Place the couscous in a heatproof bowl. Pour over the hot stock, cover and leave for 8 minutes, then fluff with a fork.', 'Mix the lemon zest, lemon juice and parsley through the couscous. Fold in the roasted vegetables and chickpeas.', 'Crumble over the feta and serve warm, or cool promptly for packed lunches.']::text[], null, 'lunch', 'Vegetarian', 'easy', true, null, 'pending', 'Colorful roasted vegetable chickpea and feta couscous in a wide cream bowl, fluffy grains, golden chickpeas, courgette, red pepper, carrot, red onion, feta and parsley, lemon wedge, bright natural daylight, elegant realistic food photography, no text, no people', 1, 'cloudflare_r2', 510, 18, 25, 20, 12, 670, 68, 13, null)
